  ('fire-eq-tech-moex-01660', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '根據各類場所消防安全設備設置標準之規定，設置5支室外消防栓設備之公共危險物品場所，下列敘述， 何者正確？', '["瞄子放水壓力範圍在3.5～6.0Kgf/cm2", "水源容量應在54立方公尺以上", "配管埋設於地下時，應採取有效防腐蝕措施。但不得使用鑄鐵管", "緊急電源供電容量應供其有效動作30分鐘以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01661', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '使用消防幫浦性能試驗裝置，進行幫浦之性能測試時，幫浦全閉點、額定點及全開點之壓力值，可由下 列何者取得？', '["幫浦入口之連成表", "流水檢知裝置一次側之壓力表", "幫浦啟動用水壓開關裝置之壓力表", "幫浦出口之壓力表"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01662', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '瓦斯漏氣火警自動警報設備，在執行性能檢查時，應確認其檢知區域警報裝置音壓應在多少分貝以上？', '["50", "70", "90", "100"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01663', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '多信號探測器以外之非再用型、局限型定溫式探測器，若探測器設置數量為60個，在執行性能檢查時， 依規定應選取幾個檢查數量？', '["2", "3", "4", "5"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01664', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依據公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法，室內儲槽場所輸送液體六類物品之配管 規定，下列何者錯誤？', '["在進行配管水壓試驗時，對設置塑材雙套管者，其耐壓試驗以外管為限", "設於地上者，不得接觸地面，且外部應有防蝕功能", "設有保溫之設備者，應具有預防火災之安全構造", "設於地下者，外部應有防蝕功能；接合部分，應有可供檢查之措施。但以熔接接合者，不在此限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01665', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依據防火牆及防火水幕設置基準，防火水幕設備之水源所連結之加壓送水裝置，下列何者正確？', '["可由消防幫浦、重力水箱及壓力水箱，依現場施工條件，視情況擇一設置", "加壓送水裝置之驅動系統不論電動機或引擎，均應連接緊急電源", "加壓送水裝置啟動後六分鐘內應能形成水幕", "水幕噴頭之放射壓力應在1.0Kgf/cm2以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01666', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法，液化石油氣儲存場所僅供一家販賣場所使 用之面積，不得少於X平方公尺。販賣場所儲放之液化石油氣備用量，供家庭使用者，不得超過Y公斤。 下列（X，Y），何者正確？', '["（6，40）", "（6，80）", "（10，40）", "（10，80）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01667', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '根據各類場所消防安全設備設置標準之規定，室內儲槽場所儲存硫磺，且屬於顯著滅火困難場所時，應 設置下列何種滅火設備？', '["水霧或泡沫滅火設備", "乾粉滅火設備", "水霧滅火設備", "泡沫滅火設備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01668', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依建築技術規則建築設計施工編之規定，下列何者非屬「居室」？', '["會議室", "廚房", "車庫", "未設置儲藏室之寄宿舍，其衣帽間面積占該層樓地板面積之20%者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01669', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '消防設備師及消防設備士，自取得證書日起每3年應接受講習一次或取得累計積分達160分以上之訓練 證明文件，有關訓練累計積分之標準，下列何者正確？', '["消防專技人員公會或全國聯合會之年會及當次達一小時以上之技術研討會，每次積分10分", "中央主管機關舉辦或認可之專業訓練課程，每小時積分10分", "於國外參加專業機構或團體舉辦國際性之講習會、研討會或專題演講領有證明文件者，每小時積分 10分，每項課程或講題總分以30分為限", "研究所以上之在職進修或推廣教育，取得學分或結業證明者，每一學分積分10分，單一課程以40分 為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
